import React, { useState, useEffect } from "react";
import { useLocation, useNavigate } from 'react-router-dom';
import axios from "axios";
import { fetchData } from "../../utils/dataUtils";
import common from "../../utils/common";
import useStore from '../../store/store';
import { hasPermission } from '../../utils/authUtils';
import ErrorMsgPopup from "../../components/popup/ErrorMsgPopup";
import styles from './Board.module.css';
import fileUtils from '../../utils/fileUtils';

const BoardWrite = () => {
  const { state } = useLocation();
  const navigate = useNavigate();
  const { user } = useStore();
  const isEdit = !!state?.notice;
  const existingFiles = state?.files || [];
  
  const initialFileInputs = existingFiles.length >= 5 ? [] : [0];
  const [title, setTitle] = useState(state?.notice?.title || '');
  const [content, setContent] = useState(state?.notice?.content || '');
  const [fileInputs, setFileInputs] = useState(initialFileInputs);
  const [files, setFiles] = useState([]);
  const [existingFilesState, setExistingFilesState] = useState(existingFiles);
  const [filesToDelete, setFilesToDelete] = useState([]);
  const [showErrorPopup, setShowErrorPopup] = useState(false);
  const [errorMessage, setErrorMessage] = useState("");
  const [loading, setLoading] = useState(false);

  const MAX_FILES = 5;
  const MAX_FILE_SIZE = 5 * 1024 * 1024;

  useEffect(() => {
    if (!user || !hasPermission(user.auth, 'mainBoard')) {
      console.log("User not authenticated or lacks permission:", user);
      navigate('/');
      return;
    }
  }, [user, navigate]);

  const handleAddFileInput = () => {
    const totalFiles = existingFilesState.length + fileInputs.length;
    if (totalFiles < MAX_FILES) {
      setFileInputs([...fileInputs, fileInputs.length]);
    }
  };

  const handleRemoveFileInput = (index) => {
    if (fileInputs.length === 1 && existingFilesState.length === 0) return;
    const newFileInputs = fileInputs.filter((_, i) => i !== index);
    const newFiles = files.filter((_, i) => i !== index);
    setFileInputs(newFileInputs.map((_, i) => i));
    setFiles(newFiles);
  };

  const handleRemoveExistingFile = async (file) => {
    if (!window.confirm('파일을 삭제하시겠습니까?')) return;

    try {
      const formData = new FormData();
      formData.append("gubun", "d");
      formData.append("fileId", file.fileId);
      formData.append("noticeId", String(state.notice.id));

      const deleteResponse = await fetchData(axios, `${common.getServerUrl("notice/filesave")}`, formData, { withCredentials: true });

      if (deleteResponse.errCd !== '00') {
        throw new Error(deleteResponse.errMsg || "파일 삭제 실패");
      }

      setExistingFilesState(existingFilesState.filter(f => f.fileId !== file.fileId));
      setFilesToDelete([...filesToDelete, file.fileId]);

      const totalFiles = existingFilesState.length - 1 + fileInputs.length;
      if (totalFiles < MAX_FILES && fileInputs.length === 0) {
        setFileInputs([0]);
      }
    } catch (error) {
      console.error('Error deleting file:', error);
      setErrorMessage(error.message || "파일 삭제 중 오류가 발생했습니다.");
      setShowErrorPopup(true);
    }
  };

  const handleFileChange = (index, e) => {
    const selectedFile = e.target.files[0];
    if (selectedFile) {
      if (selectedFile.size > MAX_FILE_SIZE) {
        setErrorMessage("파일 크기는 5MB를 초과할 수 없습니다.");
        setShowErrorPopup(true);
        return;
      }
      const newFiles = [...files];
      newFiles[index] = selectedFile;
      setFiles(newFiles);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const originalTitle = state?.notice?.title || '';
    const originalContent = state?.notice?.content || '';
    const hasTitleChanged = title !== originalTitle;
    const hasContentChanged = content !== originalContent;

    if ((!isEdit && (!title || !content)) || (isEdit && hasTitleChanged && !title) || (isEdit && hasContentChanged && !content)) {
      setErrorMessage("제목과 내용을 입력해주세요.");
      setShowErrorPopup(true);
      return;
    }

    setLoading(true);
    setErrorMessage(null);

    try {
      const gubun = isEdit ? 'U' : 'I';
      const noticeId = isEdit ? String(state.notice.id) : '0';
      const payload = {
        gubun,
        noticeId,
        title,
        content,
      };

      const saveResponse = await fetchData(axios, `${common.getServerUrl("notice/save")}`, payload, { withCredentials: true });

      if (saveResponse.errCd !== '00') {
        throw new Error(saveResponse.errMsg || "게시물 저장 실패");
      }

      const updatedNoticeId = isEdit ? noticeId : saveResponse.data?.noticeId;

      if (isEdit && filesToDelete.length > 0) {
        for (const fileId of filesToDelete) {
          const deletePayload = {
            gubun: 'D',
            noticeId: updatedNoticeId,
            fileId,
          };
          const deleteResponse = await fetchData(axios, `${common.getServerUrl("notice/save")}`, deletePayload, { withCredentials: true });
          if (deleteResponse.errCd !== '00') {
            console.error('File deletion failed:', deleteResponse.errMsg);
            throw new Error(deleteResponse.errMsg || "파일 삭제 실패");
          }
        }
      }

      if (files.length > 0 && files.some(file => file != null)) {
        const formData = new FormData();
        formData.append("gubun", "I");
        formData.append("fileId", "");
        formData.append("noticeId", updatedNoticeId);

        files.forEach((file) => {
          if (file) {
            formData.append("files", file);
          }
        });

        const uploadResponse = await fetchData(axios, `${common.getServerUrl("notice/filesave")}`, formData, { withCredentials: true });

        if (uploadResponse.errCd !== '00') {
          throw new Error(uploadResponse.errMsg || "파일 업로드 실패");
        }
      }

      alert(isEdit ? "게시물이 성공적으로 변경되었습니다." : "게시물이 성공적으로 등록되었습니다.");
      navigate('/main');
    } catch (error) {
      console.error("게시물 저장 실패:", {
        message: error.message,
        response: error.response ? {
          status: error.response.status,
          data: error.response.data,
          headers: error.response.headers
        } : 'No response received'
      });

      setErrorMessage(error.message || "게시물 저장 중 오류가 발생했습니다.");
      setShowErrorPopup(true);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async () => {
    if (!window.confirm('정말 삭제하시겠습니까?')) return;

    setLoading(true);
    try {
      // Log user state for debugging
      console.log("User state before delete:", user);
      console.log("Attempting to delete notice with ID:", state?.notice?.id);

      const noticeId = String(state.notice.id);
      const payload = {
        gubun: 'D',
        noticeId,
        title: title || '',
        content: content || '',
      };

      // Log the request details
      console.log("Sending delete request to notice/save:", payload);

      const deleteResponse = await fetchData(axios, `${common.getServerUrl("notice/save")}`, payload, { withCredentials: true });
      if (deleteResponse.errCd !== '00') {
        throw new Error(deleteResponse.errMsg || "게시물 삭제 실패");
      }

      if (existingFilesState.length > 0) {
        const filePayload = {
          gubun: 'D',
          noticeId,
          fileId: '',
        };

        console.log("Sending file delete request to notice/filesave:", filePayload);

        const fileDeleteResponse = await fetchData(axios, `${common.getServerUrl("notice/filesave")}`, filePayload, { withCredentials: true });
        if (fileDeleteResponse.errCd !== '00') {
          console.error('File deletion failed:', fileDeleteResponse.errMsg);
          throw new Error(fileDeleteResponse.errMsg || "파일 삭제 실패");
        }
      }

      alert("게시물이 성공적으로 삭제되었습니다.");
      navigate('/main');
    } catch (error) {
      console.error("게시물 삭제 실패:", error);

      setErrorMessage(error.message || "게시물 삭제 중 오류가 발생했습니다.");
      setShowErrorPopup(true);
    } finally {
      setLoading(false);
    }
  };

  const handleCloseErrorPopup = () => {
    setShowErrorPopup(false);
  };

  return (
    <div className="container bg-body">
      <h2 className={`text-primary text-dark fs-5 mb-4 pt-3 ${styles.boardTitle}`}>
        {isEdit ? '공지 변경' : '공지 등록'}
      </h2>
      <div className={styles.boardTitleLine}></div>
      <form onSubmit={handleSubmit}>
        <div className="mb-3">
          <label className="form-label">제목</label>
          <input
            className={`form-control bg-light-subtle ${styles.formControl}`}
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            placeholder="제목을 입력하세요"
            required
          />
        </div>
        <div className="mb-3">
          <label className="form-label">내용</label>
          <textarea
            className={`form-control bg-light-subtle ${styles.formControl}`}
            rows="5"
            value={content}
            onChange={(e) => setContent(e.target.value)}
            placeholder="내용을 입력하세요"
            required
          />
        </div>
        <div className="mb-4">
          <label className="form-label">
            첨부파일 <span className="text-muted">(최대 5개까지만 첨부 가능하며, 5MB까지만 됩니다.)</span>
          </label>
          {existingFilesState.length > 0 && (
            <div className="mb-3">
              <h6>기존 첨부파일:</h6>
              {existingFilesState.map((file) => (
                <div key={file.fileId} className="d-flex align-items-center mb-2">
                  <span className="me-2">
                    {file.fileName} ({fileUtils.formatFileSize(file.fileSize)})
                  </span>
                  <button
                    type="button"
                    className="btn btn-outline-danger btn-sm"
                    onClick={() => handleRemoveExistingFile(file)}
                  >
                    -
                  </button>
                </div>
              ))}
            </div>
          )}
          {fileInputs && fileInputs.length > 0 ? (
            fileInputs.map((inputId, index) => (
              <div key={inputId} className="d-flex align-items-center mb-2">
                <input
                  type="file"
                  className={`form-control bg-light-subtle ${styles.formControl} me-2`}
                  onChange={(e) => handleFileChange(index, e)}
                />
                <button
                  type="button"
                  className="btn btn-outline-danger me-2"
                  onClick={() => handleRemoveFileInput(index)}
                  disabled={fileInputs.length === 1 && existingFilesState.length === 0}
                >
                  -
                </button>
                {index === fileInputs.length - 1 && (
                  <button
                    type="button"
                    className="btn btn-outline-primary"
                    onClick={handleAddFileInput}
                    disabled={existingFilesState.length + fileInputs.length >= MAX_FILES}
                  >
                    +
                  </button>
                )}
              </div>
            ))
          ) : (
            <div>파일 입력 필드가 없습니다.</div>
          )}
          {files.length > 0 && files.some(file => file != null) && (
            <div className="mt-3">
              <h6>선택된 파일:</h6>
              <ul>
                {files.map((file, index) => (
                  file && (
                    <li key={index}>
                      {file.name} ({fileUtils.formatFileSize(file.size)})
                    </li>
                  )
                ))}
              </ul>
            </div>
          )}
        </div>
        <div className="btn-group-custom d-flex justify-content-end gap-2 mb-3 mt-5">
          <button
            type="button"
            className={`btn ${styles.btnCancel}`}
            onClick={() => navigate('/main')}
          >
            취소
          </button>
          {!isEdit ? (
            <button
              type="submit"
              className={`btn ${styles.btnReg}`}
              disabled={loading}
            >
              {loading ? "저장 중..." : "등록"}
            </button>
          ) : (
            <>
              <button
                type="submit"
                className={`btn ${styles.btnMod}`}
                disabled={loading}
              >
                {loading ? "저장 중..." : "변경"}
              </button>
              <button
                type="button"
                className={`btn btn-danger ${styles.btnMod}`}
                onClick={handleDelete}
                disabled={loading}
              >
                {loading ? "삭제 중..." : "삭제"}
              </button>
            </>
          )}
        </div>
      </form>
      <ErrorMsgPopup show={showErrorPopup} onHide={handleCloseErrorPopup} message={errorMessage} />
    </div>
  );
};

export default BoardWrite;